#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int N; scanf("%d", &N);
        long long *A = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &A[i]);
        long long *pref = (long long*)malloc((N + 1) * sizeof(long long));
        pref[0] = 0;
        for (int i = 1; i <= N; ++i) pref[i] = pref[i-1] ^ A[i-1];
        long long *ans = (long long*)calloc(N, sizeof(long long));
        for (int m = 1; m <= N; ++m) {
            long long cnt = 0;
            for (int i = 0; i + m <= N; ++i) {
                if (pref[i] == pref[i + m]) ++cnt;
            }
            ans[m-1] = cnt;
        }
        for (int i = 0; i < N; ++i) {
            printf("%lld", ans[i]);
            if (i + 1 < N) printf(" ");
        }
        printf("\n");
        free(A); free(pref); free(ans);
    }
    return 0;
}

