import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        A = [int(next(it)) for _ in range(N)]
        pref = [0]
        for x in A:
            pref.append(pref[-1] ^ x)
        ans = []
        for m in range(1, N + 1):
            cnt = 0
            for i in range(N - m + 1):
                if pref[i] == pref[i + m]:
                    cnt += 1
            ans.append(str(cnt))
        out_lines.append(' '.join(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

